<?php declare(strict_types=1);namespace Tests;use PDO;use PHPUnit\Framework\TestCase;use PreConselho\Repositories\AppRepository;use PreConselho\Services\AuthService;
final class AuthServiceTest extends TestCase{public function testLoginValido():void{$db=new PDO('sqlite::memory:');$db->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);$db->setAttribute(PDO::ATTR_DEFAULT_FETCH_MODE,PDO::FETCH_ASSOC);$db->exec((string)file_get_contents(dirname(__DIR__).'/apps/preconselho-web/database/migrations/001_initial.sql'));$db->prepare("INSERT INTO usuarios(nome,email,senha_hash,perfil)VALUES('A','a@a.com',?,'ADMIN')")->execute([password_hash('senha-segura',PASSWORD_DEFAULT)]);$u=(new AuthService(new AppRepository($db)))->login('a@a.com','senha-segura','127.0.0.1','phpunit');self::assertSame('ADMIN',$u['perfil']);}}
